from web3 import Web3


def set_opt_code(rpc):
    # Connect to the Anvil node
    w3 = Web3(Web3.HTTPProvider(rpc))

    # https://arbiscan.io/address/0x5d6b84086da6d4b0b6c0df7e02f8a6a039226530#code
    # Address of the contract to override
    contract_address = "0x5d6B84086DA6d4B0b6C0dF7E02f8a6A039226530"

    mock_bytecode = ""

    # Use Anvil's RPC to set the contract's bytecode
    response = w3.provider.make_request("tenderly_setCode", [contract_address, mock_bytecode])

    print(f"Response: {response}")
    print("Contract bytecode overridden. GmOracleUtils.validateSigner will now return true.")
